const fs = require('fs');
const path = require('path');

const dir = path.join('apps', 'roku', 'images', 'avatars');
const keys = [
  'fox', 'owl', 'frog', 'whale', 'unicorn', 'tiger', 'dragon', 'wolf',
  'lion', 'panda', 'cat', 'dog', 'bunny', 'penguin', 'dino', 'robot',
];

const out = [
  '// Auto-generated by scripts/gen-avatar-pngs.js.',
  '// Source: Twemoji 72x72 PNGs (CC-BY 4.0, jdecked/twemoji v15).',
  '// To refresh, replace the source PNGs and re-run the script.',
  '',
  'export const AVATAR_PNGS: Record<string, Buffer> = {',
];
for (const k of keys) {
  const buf = fs.readFileSync(path.join(dir, k + '.png'));
  const b64 = buf.toString('base64');
  out.push("  '" + k + "': Buffer.from('" + b64 + "', 'base64'),");
}
out.push('};');
out.push('');

const target = path.join('packages', 'api', 'src', 'services', 'avatar-pngs.ts');
fs.writeFileSync(target, out.join('\n'));
console.log('wrote', target, 'with', keys.length, 'entries');
